var e=[{id:`L2_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`제가 발을 묶겠습니다! 도망치세요 실비아 씨!`,JPN:`僕が足止めしますから！　逃げて、シルビアさん！`,ENG:`I'll keep it busy. Run, Sylvia!`,TWN:`我來拖住它！請逃走吧，希爾維亞小姐！`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`카일!`,JPN:`カイル！`,ENG:`Kyle!`,TWN:`凱爾！`},stage:{bg:`WAREHOUSE_01`,slots:{L:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`크으윽!!`,JPN:`くううっ！！`,ENG:`Ugh!`,TWN:`唔呃呃！！`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`카일! 정신차려! 괜찮아?`,JPN:`カイル！　しっかりして！　大丈夫？`,ENG:`Kyle! Wake up! You alright?`,TWN:`凱爾！振作點！你沒事吧？`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`괘, 괜찮습니다...... 이 정도는......`,JPN:`だ、大丈夫です……これくらいは……`,ENG:`I-I'm okay... I can handle this...`,TWN:`沒、沒事……這種小傷……`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`바보 같은 소리 마! 온 몸이 피투성이잖아?`,JPN:`バカ言わないでよ！　全身血だらけじゃない！`,ENG:`No, you can't! Look at you—you're bleeding all over!`,TWN:`別說傻話了！你全身都是血啊？`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`방금 녀석의 침식파 시그니처를 확인했어.`,JPN:`さっきの奴の侵食波シグネチャーを確認したわ。`,ENG:`I've checked its Corruption Ray signature.`,TWN:`我剛才確認了這傢伙的侵蝕波標誌。`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`예상대로 저건 4종 침식체라고! 이런 소규모 병력으로 어쩔 상대가 아니야!`,JPN:`案の定、あれは第4種侵食体よ！　こんな少人数の兵力じゃどうしようもない！　`,ENG:`We were right. It's Category 4. We're not equipped to fight that thing.`,TWN:`和預料得一樣，那是4類侵蝕體！以我們這種小規模兵力，是沒辦法對付它的！`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:`젠장, 어디서 저런 괴물이 튀어나온 거야?`,JPN:`くそっ、どこからあんなバケモノが現れたわけ？`,ENG:`Goddamnit, where did it come from?!`,TWN:`可惡，那種怪物是從哪裡冒出來的啊？`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`하지만...... 놈을 막지 못하면 등대가......`,JPN:`でも……奴を食い止めなければ、灯台が……`,ENG:`But... if we don't stop it, the Lighthouse...`,TWN:`可是……我們不擋下它的話，燈塔會……`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`으, 으아악!!`,JPN:`う、うわああ！！`,ENG:`W-waaah!`,TWN:`啊，啊啊啊！！`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`도, 도망쳐! 이젠 끝났어!!`,JPN:`に、逃げろ！　もうおしまいだ！！`,ENG:`R-run! It's over!`,TWN:`快、快逃！已經完蛋了！！`},stage:{bg:`WAREHOUSE_01`,slots:{L:null,C:{char_id:`AGENT_EXTRA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`MARK_NPC_NULL_NULL`,text:{KOREA:`멍청한 소리 할 시간 있으면 이거나 빨리 트럭에 실어!`,JPN:`バカ言ってる暇があるなら、これでもさっさとトラックに載せろ！`,ENG:`Stop yammering and load this on the truck!`,TWN:`有空說傻話，還不快點把它裝上卡車！`},stage:{bg:`WAREHOUSE_01`,slots:{L:{char_id:`MARK_NPC_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`AGENT_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L33_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`뭐하는 겁니까, 당장 도망가도 모자랄 판에?!`,JPN:`何を言ってるんです、今は逃げる以外の選択肢はないんじゃ！？`,ENG:`What are you doing? We have to run while we can!`,TWN:`你是要幹嘛，我們現在連逃跑都來不及了啊？！`},stage:{bg:`WAREHOUSE_01`,slots:{L:{char_id:`MARK_NPC_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`AGENT_EXTRA_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L34_1`,type:`dialog`,speaker:`MARK_NPC_NULL_NULL`,text:{KOREA:`도망칠 때 치더라도 등대는 수거해야지!`,JPN:`逃げるにしても、灯台は回収しないと！`,ENG:`We'll run, but not without the Lighthouse!`,TWN:`就算要逃跑，也要回收燈塔啊！`},stage:{bg:`WAREHOUSE_01`,slots:{L:{char_id:`MARK_NPC_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`AGENT_EXTRA_NULL_NULL`,face:`UNIT_HATE`}}}}];export{e as default};